#include <bits/stdc++.h>
using namespace std;

double myPow(double x, long long n) {
    if (n == 0) return 1.0;
    if (n < 0) {
        x = 1.0 / x;
        n = -n;
    }
    double result = 1.0;
    while (n) {
        if (n & 1) result *= x;
        x *= x;
        n >>= 1;
    }
    return result;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    double x; long long n;
    if(!(cin>>x)) return 0;
    if(!(cin>>n)) n=0;
    double res = myPow(x, n);
    // format similar to python output: trim trailing zeros
    std::ostringstream oss;
    oss.setf(std::ios::fixed); oss.precision(10);
    oss<<res;
    string s = oss.str();
    // trim trailing zeros and dot
    while(!s.empty() && s.back()=='0') s.pop_back();
    if(!s.empty() && s.back()=='.') s.pop_back();
    if(s.empty()) s="0";
    cout<<s;
    return 0;
}
